DO $$ DECLARE pagbank_id UUID; c6_id UUID; din_id UUID;
BEGIN
  SELECT id INTO pagbank_id FROM contas_financeiras WHERE tipo='pagbank_pj' LIMIT 1;
  SELECT id INTO c6_id FROM contas_financeiras WHERE tipo='c6_pf' LIMIT 1;
  SELECT id INTO din_id FROM contas_financeiras WHERE tipo='dinheiro' LIMIT 1;

END $$;